405→/// Classify whether a thrown error is a deliberate validation rejection or an
406→/// accidental runtime failure by examining the branch path immediately before the error.
407→///
408→/// Pattern: a guard branch taken=true followed immediately by the error (no intervening
409→/// branches) suggests intentional input rejection. Errors without a preceding guard
410→/// or deep in the branch path are more likely accidental.
411→pub fn classify_error_intent(result: &crate::protocol::ExecuteResult) -> Option<ErrorIntentLabel> {
412→    let error = result.thrown_error.as_ref()?;
413→
414→    // If the frontend already classified this as infrastructure, trust it
415→    if error.error_category.as_deref() == Some("infrastructure") {
416→        return Some(ErrorIntentLabel {
417→            label: "likely_runtime".into(),
418→            confidence: 0.9,
419→        });
420→    }
421→
422→    let branch_path = &result.branch_path;
423→    if branch_path.is_empty() {
424→        // No branch data — can't infer intent
425→        return Some(ErrorIntentLabel {
426→            label: "unknown".into(),
427→            confidence: 0.0,
428→        });
429→    }
430→
431→    // Check the last branch before the error
432→    let last_branch = branch_path.last().unwrap();
433→
434→    // Guard pattern: last branch taken=true, suggesting an if-guard that led to a throw.
435→    // Shallow depth (few branches) + guard = likely validation.
436→    if last_branch.taken && branch_path.len() <= 3 {
437→        return Some(ErrorIntentLabel {
438→            label: "likely_validation".into(),
439→            confidence: 0.7,
440→        });
441→    }
442→
443→    // Deep branch path with error = likely accidental runtime failure
444→    if branch_path.len() > 5 {
445→        return Some(ErrorIntentLabel {
446→            label: "likely_runtime".into(),
447→            confidence: 0.6,
448→        });
449→    }
450→
451→    // Frontend-level classification can help disambiguate
452→    if error.error_category.as_deref() == Some("validation") {
453→        return Some(ErrorIntentLabel {
454→            label: "likely_validation".into(),
455→            confidence: 0.8,
456→        });
457→    }
458→    if error.error_category.as_deref() == Some("runtime") {
459→        return Some(ErrorIntentLabel {
460→            label: "likely_runtime".into(),
461→            confidence: 0.7,
462→        });
463→    }
464→
465→    Some(ErrorIntentLabel {
466→        label: "unknown".into(),
467→        confidence: 0.3,
468→    })
469→}
