155→/// An entry in the exploration worklist.
156→#[derive(Debug, Clone)]
157→pub struct WorklistEntry {
158→    /// Input values to pass to the function.
159→    pub inputs: Vec<serde_json::Value>,
160→    /// How these inputs were generated.
161→    pub source: InputSource,
162→    /// Optional fitness score (0.0–1.0) from genetic scoring.
163→    ///
164→    /// When present, fitness is the primary ordering key for the worklist's
165→    /// BinaryHeap. When absent (`None`), the entry falls back to source-based
166→    /// ordering, which preserves backward compatibility with the pre-genetic
167→    /// pipeline.
168→    pub fitness: Option<f64>,
169→    /// Per-entry mock configurations for dynamic mock variation.
170→    /// When non-empty, these override `ExploreConfig::mocks` for this execution.
171→    pub mock_values: Vec<MockConfig>,
172→}
173→
174→impl Eq for WorklistEntry {}
175→
176→impl PartialEq for WorklistEntry {
177→    fn eq(&self, other: &Self) -> bool {
178→        self.source == other.source && self.fitness_key() == other.fitness_key()
179→    }
180→}
181→
182→impl PartialOrd for WorklistEntry {
183→    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
184→        Some(self.cmp(other))
185→    }
186→}
187→
188→impl Ord for WorklistEntry {
189→    /// Primary ordering: fitness score (higher is better). Entries with a
190→    /// fitness score always outrank entries without one. Among entries without
191→    /// fitness, the original source-based priority applies.
192→    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
193→        match (self.fitness, other.fitness) {
194→            (Some(_), None) => std::cmp::Ordering::Greater,
195→            (None, Some(_)) => std::cmp::Ordering::Less,
196→            (Some(_), Some(_)) => self
197→                .fitness_key()
198→                .cmp(&other.fitness_key())
199→                .then_with(|| self.source.cmp(&other.source)),
200→            (None, None) => self.source.cmp(&other.source),

 758→pub async fn explore(
 759→    frontend: &mut Frontend,
 760→    function_name: &str,
 761→    seed_inputs: Vec<Vec<serde_json::Value>>,
 762→    user_inputs: Vec<Vec<serde_json::Value>>,
 763→    param_infos: &[ParamInfo],
 764→    config: &ExploreConfig,
 765→    setup_context: Option<SetupContextStack>,
 766→) -> Result<ExploreResult, ExploreError> {
 767→    let param_names: Vec<String> = param_infos.iter().map(|p| p.name.clone()).collect();
 768→    let mut worklist = BinaryHeap::new();
 769→    let mut covered_paths: HashSet<u64> = HashSet::new();
 770→    let mut executions = Vec::new();
 771→    let mut raw_results: Vec<(Vec<serde_json::Value>, Vec<MockConfig>, ExecuteResult)> = Vec::new();
 772→    let mut seen_branch_ids: HashSet<u32> = HashSet::new();
 773→    let mut discoveries: Vec<(u32, DiscoveryMethod)> = Vec::new();
 774→    let mut total_executions: usize = 0;
 775→    let mut z3_generated: usize = 0;
 776→    let mut fuzz_generated: usize = 0;
 777→    let mut boundary_generated: usize = 0;
 778→    let mut drill_generated: usize = 0;
 779→    let mut termination_reason = TerminationReason::WorklistExhausted;
 780→    let mut seen_branch_sides: HashSet<(u32, bool)> = HashSet::new();
 781→    let mut frontier_set = FrontierSet::new();
 782→    let mut rng = StdRng::from_os_rng();
 783→    let mut triage_state = TriageState::new(param_names.clone());
 784→    let mut triage_skipped: usize = 0;
 785→    let mut triage_mispredictions: usize = 0;
 786→
 787→    // Fitness context shares novelty state with covered_paths — the
 788→    // orchestrator marks paths as seen in both sets whenever a new path
 789→    // is discovered, keeping FitnessContext's novelty scoring in sync.
 790→    let mut fitness_context = FitnessContext::new();
 791→    let fitness_weights = FitnessWeights::default();
 792→
 793→    // Target branches: branch IDs seen so far on only one side (not yet
 794→    // covered on the opposite). Updated after each new-path observation.
 795→    // Used by fitness scoring to compute proximity/coverage scores.
 796→    let mut target_branches: HashSet<u32> = HashSet::new();
 797→
 798→    // MetaStrategy integration point: strategies will be registered here
 799→    // by a follow-up issue that replaces the hardcoded seed/fuzz/drill
 800→    // generation with adaptive strategy selection.
 801→    let _meta_strategy: MetaStrategy = MetaStrategy::new(vec![], Default::default());
 802→
 803→    // Generate initial mock values when mock_params are configured.
 804→    let initial_mocks = if !config.mock_params.is_empty() {
 805→        input_gen::generate_mock_values(&config.mock_params, &mut rng, None)
 806→    } else {
 807→        vec![]
 808→    };
 809→
 810→    // Add user-provided candidates with highest priority.
 811→    for inputs in user_inputs {
 812→        worklist.push(WorklistEntry {
 813→            inputs,
 814→            source: InputSource::UserProvided,
 815→            fitness: None,
 816→            mock_values: initial_mocks.clone(),
 817→        });
 818→    }
 819→
 820→    // Seed the worklist.
 821→    for inputs in seed_inputs {
 822→        worklist.push(WorklistEntry {
 823→            inputs,
 824→            source: InputSource::Seed,
 825→            fitness: None,
 826→            mock_values: initial_mocks.clone(),
 827→        });
 828→    }
 829→
 830→    // --- Float probe phase ---
 831→    let float_indices = crate::float_probe::float_param_indices(param_infos);
 832→    let mut float_probe_results: Vec<crate::float_probe::FloatProbeResult> = Vec::new();
 833→    if !float_indices.is_empty() {
 834→        for &idx in &float_indices {
 835→            let pairs = crate::float_probe::generate_probe_pairs(
 836→                param_infos,
 837→                idx,
 838→                crate::float_probe::PROBE_COUNT,
 839→                &mut rng,
 840→            );
 841→            let mut agreements = 0usize;
 842→            let mut total_probes = 0usize;
 843→            let mut divergent_values = Vec::new();
 844→
 845→            for (float_inputs, floor_inputs) in pairs {
 846→                let float_resp = frontend
 847→                    .send(Command::Execute {
 848→                        function: function_name.to_string(),
 849→                        inputs: float_inputs.clone(),
 850→                        mocks: config.mocks.clone(),
 851→                        setup_context: setup_context.clone(),
 852→                    })
 853→                    .await?;
 854→
 855→                let floor_resp = frontend
 856→                    .send(Command::Execute {
 857→                        function: function_name.to_string(),
 858→                        inputs: floor_inputs,
 859→                        mocks: config.mocks.clone(),
 860→                        setup_context: setup_context.clone(),
 861→                    })
 862→                    .await?;
 863→
 864→                if let (
 865→                    ResponseResult::Execute(float_result),
 866→                    ResponseResult::Execute(floor_result),
 867→                ) = (&float_resp.result, &floor_resp.result)
 868→                {
 869→                    total_probes += 1;
 870→
 871→                    if crate::float_probe::executions_agree(float_result, floor_result) {
 872→                        agreements += 1;
 873→                    } else if let Some(v) = float_inputs.get(idx).and_then(|v| v.as_f64()) {
 874→                        divergent_values.push(v);
 875→                    }
 876→                }
 877→            }
 878→
 879→            let classification = crate::float_probe::classify(
 880→                agreements,
 881→                total_probes,
 882→                crate::float_probe::AGREEMENT_THRESHOLD,
 883→            );
 884→            float_probe_results.push(crate::float_probe::FloatProbeResult {
 885→                param_index: idx,
 886→                param_name: param_infos[idx].name.clone(),
 887→                classification,
 888→                agreements,
 889→                total_probes,
 890→                divergent_values,
 891→            });
 892→        }
 893→    }
 894→
 895→    let explore_start = Instant::now();
 896→    let mut plateau_counter: usize = 0;
 897→
 898→    // --- Two-phase exploration loop: Observe → Solve/Generate ---
 899→    //
 900→    // Each iteration processes one worklist entry:
 901→    //   1. Observe — execute the entry, classify the path
 902→    //   2. Solve/Generate — if new path, extract constraints and produce candidates
 903→    //
 904→    // Solving after each observation (not batched) preserves the original
 905→    // convergence behavior: Z3 candidates from observation N are available
 906→    // for execution at iteration N+1.
 907→    while let Some(entry) = worklist.pop() {
 908→        // Phase 1: Observe — execute and classify one worklist entry.
 909→        let budget = ExploreBudget {
 910→            unique_paths: executions.len(),
 911→            total_executions,
 912→            plateau_counter,
 913→            explore_start,
 914→        };
 915→
 916→        let observe_result = observe_one(
 917→            &entry,
 918→            frontend,
 919→            function_name,
 920→            config,
 921→            &mut covered_paths,
 922→            &mut triage_state,
 923→            &budget,
 924→            &setup_context,
 925→        )
 926→        .await?;
 927→
 928→        let obs = match observe_result {
 929→            ObserveOneResult::Observed(obs) => *obs,
 930→            ObserveOneResult::TriageSkipped => {
 931→                triage_skipped += 1;
 932→                continue;
 933→            }
 934→            ObserveOneResult::FrontendSkipped => {
 935→                total_executions += 1;
 936→                continue;
 937→            }
 938→            ObserveOneResult::Terminated(reason) => {
 939→                termination_reason = reason;
 940→                break;
 941→            }
 942→        };
 943→
 944→        total_executions += 1;
 945→        if obs.is_sampled_skip && !obs.is_new_path {
 946→            // Prediction was correct (duplicate path) — no misprediction.
 947→        } else if obs.is_sampled_skip && obs.is_new_path {
 948→            triage_mispredictions += 1;
 949→        }
 950→
 951→        // Record raw result for pipeline composability.
 952→        // Use the per-execution mock values so downstream consumers see exactly
 953→        // which mocks were active for each execution.
 954→        let recorded_mocks = if obs.mock_values.is_empty() {
 955→            config.mocks.clone()
 956→        } else {
 957→            obs.mock_values.clone()
 958→        };
 959→        raw_results.push((obs.inputs.clone(), recorded_mocks, obs.result.clone()));
 960→
 961→        if !obs.is_new_path {
 962→            plateau_counter += 1;
 963→            continue;
 964→        }
 965→
 966→        // New path discovered — reset plateau counter.
 967→        plateau_counter = 0;
 968→
 969→        // Track per-branch discovery attribution.
 970→        let method = match obs.source {
 971→            InputSource::Z3Solved => DiscoveryMethod::Z3,
 972→            InputSource::UserProvided => DiscoveryMethod::UserProvided,
 973→            InputSource::Drilled => DiscoveryMethod::Drilled,
 974→            InputSource::BoundarySearch => DiscoveryMethod::BoundarySearch,
 975→            InputSource::Seed | InputSource::Fuzzed => DiscoveryMethod::Random,
 976→        };
 977→        for decision in &obs.result.branch_path {
 978→            if seen_branch_ids.insert(decision.branch_id) {
 979→                discoveries.push((decision.branch_id, method));
 980→            }
 981→        }
 982→
 983→        // Update frontier set and target branches: track which branch sides
 984→        // have been seen. Branches seen on only one side are targets for
 985→        // fitness scoring.
 986→        for decision in &obs.result.branch_path {
 987→            seen_branch_sides.insert((decision.branch_id, decision.taken));
 988→            let opposite_seen =
 989→                seen_branch_sides.contains(&(decision.branch_id, !decision.taken));
 990→            if opposite_seen {
 991→                frontier_set.remove(decision.branch_id);
 992→                target_branches.remove(&decision.branch_id);
 993→            } else {
 994→                target_branches.insert(decision.branch_id);
 995→                let prev_stall = frontier_set
 996→                    .iter()
 997→                    .find(|f| f.branch_id == decision.branch_id)
 998→                    .map_or(0, |f| f.stall_count);
 999→                let blocking =
1000→                    drilling::identify_blocking_params(&decision.constraint, param_infos);
1001→                let depth =
1002→                    drilling::branch_depth(&obs.result.branch_path, decision.branch_id);
1003→                frontier_set.insert(Frontier {
1004→                    branch_id: decision.branch_id,
1005→                    depth,
1006→                    blocking_params: blocking,
1007→                    best_prefix: obs.inputs.clone(),

1000→                    drilling::identify_blocking_params(&decision.constraint, param_infos);
1001→                let depth =
1002→                    drilling::branch_depth(&obs.result.branch_path, decision.branch_id);
1003→                frontier_set.insert(Frontier {
1004→                    branch_id: decision.branch_id,
1005→                    depth,
1006→                    blocking_params: blocking,
1007→                    best_prefix: obs.inputs.clone(),
1008→                    stall_count: prev_stall,
1009→                });
1010→            }
1011→        }
1012→
1013→        // Sync fitness context: mark this path as seen so future fitness
1014→        // scoring correctly identifies repeat paths as non-novel.
1015→        fitness_context.mark_seen(obs.path_id);
1016→
1017→        executions.push(obs.result.clone());
1018→
1019→        // Phase 2: Solve/Generate — produce new candidates from this observation.
1020→        let solve_output = solve_and_generate(
1021→            &[obs],
1022→            &mut frontier_set,
1023→            param_infos,
1024→            &param_names,
1025→            &raw_results,
1026→            &seen_branch_sides,
1027→            config,
1028→            &mut rng,
1029→            &target_branches,
1030→            &mut fitness_context,
1031→            &fitness_weights,
1032→            &config.mock_params,
1033→        );
1034→
1035→        z3_generated += solve_output.z3_count;
1036→        fuzz_generated += solve_output.fuzz_count;
1037→        drill_generated += solve_output.drill_count;
1038→        boundary_generated += solve_output.boundary_count;
1039→
1040→        for candidate in solve_output.candidates {
1041→            worklist.push(candidate);
1042→        }
1043→    }
1044→
1045→    let unique_paths = covered_paths.len();
1046→    Ok(ExploreResult {
1047→        function_name: function_name.to_string(),
1048→        total_lines: 0, // Caller must set from FunctionAnalysis (end_line - start_line + 1)
1049→        executions,
1050→        unique_paths,
1051→        total_executions,
1052→        z3_generated,
1053→        fuzz_generated,
1054→        boundary_generated,
1055→        drill_generated,
1056→        termination_reason,
1057→        raw_results,
1058→        discoveries,
1059→        triage_skipped,
1060→        triage_mispredictions,
1061→        nondeterministic_fields: vec![],
1062→        float_probe_results,
1063→    })
1064→}
